package com.chaobo.scm.supplier.application.score;
import org.junit.jupiter.api.Test;import java.math.BigDecimal;import java.util.List;import static org.assertj.core.api.Assertions.*;
class SupplierScoringDomainServiceTest{@Test void shouldCalculateExplainableWeightedScore(){var rules=List.of(new SupplierScoringDomainService.Rule("QUALITY","PASS_RATE",new BigDecimal("0.6"),new BigDecimal("0.98"),1),new SupplierScoringDomainService.Rule("DELIVERY","DELAY_RATE",new BigDecimal("0.4"),new BigDecimal("0.02"),2));var facts=List.of(new SupplierScoringDomainService.Fact("PASS_RATE",new BigDecimal("0.931")),new SupplierScoringDomainService.Fact("DELAY_RATE",new BigDecimal("0.04")));var result=SupplierScoringDomainService.calculate(rules,facts,BigDecimal.ZERO);assertThat(result.total()).isEqualByComparingTo("77.00");assertThat(result.dimensions()).containsKeys("QUALITY","DELIVERY");}@Test void shouldRejectInvalidWeightSum(){var rules=List.of(new SupplierScoringDomainService.Rule("Q","M",new BigDecimal("0.8"),BigDecimal.ONE,1));assertThatThrownBy(()->SupplierScoringDomainService.calculate(rules,List.of(),BigDecimal.ZERO)).hasMessageContaining("权重");}}
